    ('Earrings',    'w-earrings',    'Silver earrings for women — studs, jhumkas, drops, hoops and temple designs.',                   'https://cdn.hadha.co/categories/w-earrings.jpg',    '1', 'Silver Earrings for Women | Hadha.co',       'Buy handcrafted 925 silver earrings for women. Studs, jhumkas, drops and temple designs at Hadha.co.'),
    ('Bangles',     'w-bangles',     'Sterling silver bangles — minimal, oxidised, CZ-studded and temple designs.',                    'https://cdn.hadha.co/categories/w-bangles.jpg',     '2', 'Silver Bangles for Women | Hadha.co',        'Shop beautiful 925 silver bangles. Minimal, oxidised, CZ-studded and temple styles at Hadha.co.'),
    ('Chains',      'w-chains',      'Elegant silver chains and necklaces — box, rope, figaro, ball and herringbone styles.',          'https://cdn.hadha.co/categories/w-chains.jpg',      '3', 'Silver Chains for Women | Hadha.co',         'Buy sterling silver chains for women. Box, rope, figaro, ball and herringbone designs.'),
    ('Rings',       'w-rings',       'Silver rings for women — infinity, solitaire, floral, temple and adjustable designs.',           'https://cdn.hadha.co/categories/w-rings.jpg',       '4', 'Silver Rings for Women | Hadha.co',          'Shop 925 silver rings for women. Infinity, solitaire, floral and temple designs.'),
    ('Bugadi',      'w-bugadi',      'Traditional Maharashtrian silver bugadi (nose rings) — classic, floral and CZ designs.',         'https://cdn.hadha.co/categories/w-bugadi.jpg',      '5', 'Silver Bugadi | Hadha.co',                   'Buy traditional Maharashtrian silver bugadi. Classic, floral and CZ designs at Hadha.co.'),
    ('Anklets',     'w-anklets',     'Silver anklets (payal) — classic, ghungroo, floral, minimal and temple styles.',                'https://cdn.hadha.co/categories/w-anklets.jpg',     '6', 'Silver Anklets for Women | Hadha.co',        'Shop 925 silver anklets for women. Classic, ghungroo, floral and temple payal designs.'),
    ('Nakshi Mala', 'w-nakshi-mala', 'Handcrafted Nakshi silver necklaces — traditional haar, choker, mala and bridal sets.',         'https://cdn.hadha.co/categories/w-nakshi-mala.jpg', '7', 'Nakshi Silver Mala | Hadha.co',              'Buy handcrafted Nakshi silver mala and necklaces. Traditional haar, choker and bridal designs.'),
    ('Black Beads', 'w-black-beads', 'Traditional black bead silver jewellery — mangalsutra, nazariya, wati and necklaces.',          'https://cdn.hadha.co/categories/w-black-beads.jpg', '8', 'Black Bead Silver Jewellery | Hadha.co',     'Shop traditional black bead silver jewellery. Mangalsutra, nazariya and wati designs.'),
    ('Gifts',       'w-gifts',       'Curated silver jewellery gift sets for women — perfect for birthdays, festivals and weddings.',  'https://cdn.hadha.co/categories/w-gifts.jpg',       '9', 'Silver Jewellery Gifts for Women | Hadha.co', 'Shop curated silver jewellery gift sets for women. Perfect for birthdays and weddings.')
