INSERT INTO public.products (
    sku, name, slug, description, short_description, category_id,
    metal_type, purity, hallmark_number, weight_grams, making_charges, wastage_percent,
    gender, base_price, compare_at_price, cost_price, tax_rate, hsn_code,
    stock_quantity, status, is_featured, is_new_arrival, is_best_seller,
    meta_title, meta_description, meta_keywords, published_at
)
SELECT
    v.sku, v.name, v.slug, v.description, v.short_desc, c.id,
    v.metal, v.purity, v.hallmark,
    v.wt::numeric(10,3), v.making::numeric(12,2), v.wastage::numeric(5,2),
    v.gender,
    v.price::numeric(12,2), v.compare::numeric(12,2), v.cost::numeric(12,2),
    3.0, '7113',
    v.stock::int, 'active',
    (v.featured = 'true'), (v.new_arr = 'true'), (v.bestseller = 'true'),
    v.meta_title, v.meta_desc, v.meta_kw,
    NOW()
FROM (VALUES
    -- WOMEN EARRINGS
    ('HD-WER-0001','Lotus Silver Stud','lotus-silver-stud','Handcrafted 925 sterling silver lotus stud earrings with intricate filigree petals. Lightweight and comfortable for daily wear. BIS hallmarked and skin-friendly.','Delicate lotus stud in 925 sterling silver with fine filigree detailing. Perfect for daily wear.','w-earrings','925 Silver','925','BIS925WER001','3.0','150.00','5.0','women','999','1299','599','30','false','true','false','Lotus Silver Stud Earrings | Hadha.co','Buy handcrafted lotus silver stud earrings in 925 sterling silver. Lightweight, BIS hallmarked and perfect for daily wear.','lotus silver stud, silver stud earrings, 925 silver earrings, women earrings, daily wear earrings'),
    ('HD-WER-0002','Peacock CZ Jhumka','peacock-cz-jhumka','Stunning peacock-inspired silver jhumka earrings embellished with cubic zirconia stones. Traditional craftsmanship meets contemporary design. Ideal for festive and bridal occasions.','Peacock silver jhumka with CZ stones. Festive and bridal occasion earrings in 925 silver.','w-earrings','925 Silver','925','BIS925WER002','5.0','250.00','5.0','women','1499','1899','899','25','true','true','false','Peacock CZ Jhumka Silver Earrings | Hadha.co','Shop peacock CZ jhumka earrings in 925 silver. Traditional design with cubic zirconia for festive occasions.','peacock jhumka, CZ jhumka, silver jhumka, festive earrings, bridal earrings, 925 silver'),
    ('HD-WER-0003','Temple Jhumka Silver','temple-jhumka-silver','Magnificent temple-style silver jhumka earrings inspired by South Indian temple art. Featuring deity motifs and intricate granulation work. A statement piece for traditional occasions.','Temple-style silver jhumka with deity motifs and granulation work. Statement earrings for traditional wear.','w-earrings','925 Silver','925','BIS925WER003','6.0','300.00','5.0','women','1799','2299','1079','20','false','false','true','Temple Jhumka Silver Earrings | Hadha.co','Buy temple-style silver jhumka earrings. Deity motifs and granulation work for traditional occasions.','temple jhumka, temple silver earrings, south indian earrings, traditional jhumka, 925 silver'),
    ('HD-WER-0004','Floral Filigree Stud','floral-filigree-stud','Elegant floral filigree stud earrings handcrafted in 925 sterling silver. The open lacework design gives a lightweight feel despite the intricate detailing. Perfect for office and casual wear.','Handcrafted floral filigree stud in 925 silver. Lightweight lace design for office and casual wear.','w-earrings','925 Silver','925','BIS925WER004','2.0','120.00','4.0','women','799','999','479','35','false','false','true','Floral Filigree Stud Earrings Silver | Hadha.co','Shop floral filigree stud earrings in 925 sterling silver. Lightweight lace design perfect for office wear.','floral filigree stud, silver filigree earrings, office wear earrings, lightweight earrings, 925 silver'),
    ('HD-WER-0005','Pearl Drop Earrings Silver','pearl-drop-earrings-silver','Graceful silver drop earrings featuring lustrous freshwater pearl accents set in 925 sterling silver. The elegant hook design drapes beautifully and adds a touch of sophistication.','Pearl drop earrings in 925 silver with freshwater pearl accents. Elegant for parties and formal events.','w-earrings','925 Silver','925','BIS925WER005','4.0','200.00','5.0','women','1299','1699','779','3','false','false','false','Pearl Drop Silver Earrings | Hadha.co','Buy silver drop earrings with pearl accents in 925 sterling silver. Elegant design for parties and formal events.','pearl drop earrings, silver pearl earrings, drop earrings, party earrings, 925 silver'),
    -- WOMEN BANGLES
    ('HD-WBA-0001','Oxidised Floral Bangle','oxidised-floral-bangle','Beautifully oxidised 925 silver bangle with hand-carved floral motifs. The antique finish highlights every petal and leaf in stunning detail. Ideal for ethnic and fusion outfits.','Oxidised 925 silver bangle with hand-carved floral motifs. Perfect for ethnic and fusion outfits.','w-bangles','Oxidised Silver','925','BIS925WBA001','15.0','350.00','6.0','women','1499','1899','899','28','false','true','false','Oxidised Floral Silver Bangle | Hadha.co','Shop oxidised silver bangle with floral motifs. Antique finish hand-carved detail in 925 silver.','oxidised silver bangle, floral bangle, antique silver bangle, ethnic bangle, 925 silver'),
    ('HD-WBA-0002','Minimal Silver Bangle','minimal-silver-bangle','Sleek and modern 925 sterling silver bangle with a smooth polished finish. A minimal design that pairs effortlessly with any outfit, from casual to formal. Lightweight and comfortable for daily wear.','Sleek polished 925 silver bangle with minimal design. Lightweight and versatile for daily wear.','w-bangles','925 Silver','925','BIS925WBA002','10.0','200.00','5.0','women','999','1299','599','40','false','false','true','Minimal Silver Bangle | Hadha.co','Buy minimal polished silver bangle in 925 sterling silver. Lightweight and versatile for daily wear.','minimal silver bangle, plain silver bangle, daily wear bangle, 925 silver, polished bangle'),
    ('HD-WBA-0003','Temple Design Bangle','temple-design-bangle','Exquisite temple-design 925 silver bangle featuring intricate deity motifs and floral borders. Handcrafted by skilled artisans, a masterpiece of traditional jewellery making.','Temple-design 925 silver bangle with deity motifs. Handcrafted for festive and bridal occasions.','w-bangles','925 Silver','925','BIS925WBA003','18.0','450.00','6.0','women','1999','2499','1199','18','true','false','false','Temple Design Silver Bangle | Hadha.co','Shop temple-design silver bangle in 925 silver. Intricate deity motifs handcrafted for festive occasions.','temple bangle, temple silver bangle, bridal bangle, festive bangle, 925 silver'),
    ('HD-WBA-0004','Twisted Rope Bangle','twisted-rope-bangle','Classic twisted rope design 925 sterling silver bangle. The spiral pattern creates a visually dynamic piece that reflects light beautifully. Sturdy construction suitable for daily wear.','Twisted rope design 925 silver bangle. Spiral pattern that reflects light — great for daily wear.','w-bangles','925 Silver','925','BIS925WBA004','12.0','280.00','5.0','women','1299','1699','779','32','false','true','false','Twisted Rope Silver Bangle | Hadha.co','Buy twisted rope design silver bangle in 925 sterling silver. Classic spiral pattern for daily wear.','twisted silver bangle, rope bangle, 925 silver bangle, daily wear bangle, spiral bangle'),
    ('HD-WBA-0005','CZ Studded Bangle','cz-studded-bangle','Glamorous 925 silver bangle studded with brilliant cubic zirconia stones along the top face. The stones are precision-set to maximise sparkle. Perfect for weddings and special occasions.','925 silver bangle studded with CZ stones. Maximum sparkle for weddings and special occasions.','w-bangles','925 Silver','925','BIS925WBA005','20.0','550.00','6.0','women','2499','2999','1499','2','true','false','true','CZ Studded Silver Bangle | Hadha.co','Shop CZ studded silver bangle in 925 sterling silver. Brilliant cubic zirconia for weddings and occasions.','CZ bangle, cubic zirconia bangle, studded silver bangle, wedding bangle, 925 silver'),
    -- WOMEN CHAINS
    ('HD-WCH-0001','Box Link Silver Chain','box-link-silver-chain','Classic box link chain in 925 sterling silver, featuring smooth square links that lie flat and catch light beautifully. Versatile enough to wear alone or with a pendant. Secure lobster clasp.','Classic box link 925 silver chain. Wear alone or with a pendant — secure lobster clasp closure.','w-chains','925 Silver','925','BIS925WCH001','8.0','200.00','5.0','women','1299','1699','779','35','false','false','true','Box Link Silver Chain | Hadha.co','Buy box link silver chain in 925 sterling silver. Versatile chain for daily wear or with pendants.','box link chain, silver chain, 925 silver chain, women necklace, daily wear chain'),
    ('HD-WCH-0002','Rope Necklace Silver','rope-necklace-silver','Elegant rope twist necklace crafted in 925 sterling silver. The intertwined design creates depth and texture that catches the eye from every angle. A timeless piece for any wardrobe.','Rope twist 925 silver necklace. Intertwined design with depth and texture — timeless style.','w-chains','925 Silver','925','BIS925WCH002','10.0','280.00','5.0','women','1799','2299','1079','22','false','true','false','Rope Necklace Silver | Hadha.co','Shop rope twist silver necklace in 925 sterling silver. Timeless intertwined design for women.','rope necklace, rope chain, silver necklace, 925 silver, women chain, twist chain'),
    ('HD-WCH-0003','Figaro Silver Chain','figaro-silver-chain','Traditional Italian figaro chain in 925 sterling silver — alternating small round and elongated links create a distinctive rhythmic pattern. A jewellery wardrobe essential.','Italian figaro chain in 925 silver. Alternating round and elongated links — a wardrobe essential.','w-chains','925 Silver','925','BIS925WCH003','9.0','240.00','5.0','women','1499','1899','899','30','false','false','false','Figaro Silver Chain | Hadha.co','Buy figaro silver chain in 925 sterling silver. Traditional Italian pattern in alternating link design.','figaro chain, silver figaro, 925 silver chain, italian chain, women necklace'),
    ('HD-WCH-0004','Ball Chain Necklace Silver','ball-chain-necklace-silver','Delicate silver ball chain necklace in 925 sterling silver. The perfectly round beads create a simple yet elegant look. Lightweight and ideal for minimalists who prefer understated jewellery.','Delicate ball chain in 925 silver. Round beads for a simple elegant look — ideal for minimalists.','w-chains','925 Silver','925','BIS925WCH004','6.0','160.00','4.0','women','999','1299','599','45','false','true','false','Ball Chain Necklace Silver | Hadha.co','Shop ball chain necklace in 925 sterling silver. Delicate round bead design for minimalist style.','ball chain, silver ball chain, minimalist necklace, 925 silver, bead chain'),
    ('HD-WCH-0005','Herringbone Silver Chain','herringbone-silver-chain','Luxurious herringbone chain in 925 sterling silver with a flat ribbon-like design that lies perfectly smooth against the skin. The polished surface creates a mirror-like effect. Statement necklace.','Herringbone 925 silver chain with flat ribbon design and mirror-like polished finish. Statement necklace.','w-chains','925 Silver','925','BIS925WCH005','12.0','350.00','5.0','women','2499','2999','1499','12','true','false','true','Herringbone Silver Chain | Hadha.co','Buy herringbone silver chain in 925 sterling silver. Flat ribbon design with mirror-like polished finish.','herringbone chain, flat chain, silver necklace, statement necklace, 925 silver'),
    -- WOMEN RINGS
