JOIN public.products p ON p.sku = v.p_sku
WHERE NOT EXISTS (
    SELECT 1 FROM public.product_images pi2
    WHERE pi2.product_id = p.id AND pi2.sort_order = v.so::int
);

-- ================================================================
-- STEP 9: PRODUCT ATTRIBUTES
-- ================================================================

-- 9A: Metal, Purity, Hallmark — identical for all 105 products
INSERT INTO public.product_attributes (product_id, name, value, sort_order)
SELECT p.id, a.name, a.value, a.so
FROM public.products p
CROSS JOIN (VALUES
    ('Metal',    '925 Sterling Silver', 1),
    ('Purity',   '92.5%',              2),
    ('Hallmark', 'BIS Hallmarked',      3)
) AS a(name, value, so)
WHERE p.sku LIKE 'HD-%'
ON CONFLICT ON CONSTRAINT uq_product_attributes_product_name DO NOTHING;

-- 9B: Gender — derived from SKU prefix
INSERT INTO public.product_attributes (product_id, name, value, sort_order)
SELECT p.id, 'Gender',
    CASE WHEN p.sku LIKE 'HD-W%' THEN 'Women'
         WHEN p.sku LIKE 'HD-M%' THEN 'Men'
         ELSE 'Kids' END,
    4
FROM public.products p
WHERE p.sku LIKE 'HD-%'
ON CONFLICT ON CONSTRAINT uq_product_attributes_product_name DO NOTHING;

